import { describe, expect, it } from '@a0n/gnosis/test';

import { assessVoidDimension } from './void-dimensions';

describe('void-dimensions', () => {
  it('records cross-file gaps as lower-bound invisible crossings by default', () => {
    const assessment = assessVoidDimension({
      dimension: 'cross_file',
      visibleCrossings: 0,
      intermoduleEdges: 2,
    });

    expect(assessment.invisibleCrossings).toBe(2);
    expect(assessment.totalCrossings).toBe(2);
    expect(assessment.gapIsLowerBound).toBe(true);
    expect(assessment.supportingTheorems).toContain(
      'THM-INTERMODULE-GAP-EXACT'
    );
  });

  it('supports exact temporal witnesses when queue depth is known', () => {
    const assessment = assessVoidDimension({
      dimension: 'temporal',
      visibleCrossings: 1,
      queueDepth: 3,
      exactWitness: true,
    });

    expect(assessment.invisibleCrossings).toBe(3);
    expect(assessment.totalCrossings).toBe(4);
    expect(assessment.gapIsLowerBound).toBe(false);
  });

  it('adds data-plane crossings on top of visible control crossings', () => {
    const assessment = assessVoidDimension({
      dimension: 'data_plane',
      visibleCrossings: 2,
      dataCrossings: 3,
    });

    expect(assessment.invisibleCrossings).toBe(3);
    expect(assessment.totalCrossings).toBe(5);
    expect(assessment.rationale).toContain('data-plane');
  });
});
